// Google Ads API not configured — graceful skip
return [{ json: {
  status: 'skipped',
  reason: 'Google Ads not configured — set TG_GOOGLE_ADS_CUSTOMER_ID to enable budget monitoring',
  timestamp: new Date().toISOString()
} }];

// Calculate today's date for spend lookup
const now = new Date();
const today = now.toISOString().split('T')[0];
return [{ json: { today, nowIso: now.toISOString() } }];

// Compare total daily spend vs budget
// Budget from n8n variable TG_GOOGLE_ADS_DAILY_BUDGET (default $50)
const response = $input.first().json;
const rows = response.body || response || [];

const dailyBudget = parseFloat($vars.TG_GOOGLE_ADS_DAILY_BUDGET || '50');

if (!Array.isArray(rows) || rows.length === 0) {
  return [{ json: { status: 'no_data', totalSpend: 0, dailyBudget, pctUsed: 0 } }];
}

// Sum total spend across all campaigns
const totalSpend = rows.reduce((sum, r) => sum + (parseFloat(r.cost) || 0), 0);
const pctUsed = dailyBudget > 0 ? Math.round((totalSpend / dailyBudget) * 10000) / 100 : 0;

// Per-campaign breakdown
const campaignSpend = {};
for (const row of rows) {
  const name = row.campaign_name || row.campaign_id || 'unknown';
  campaignSpend[name] = (campaignSpend[name] || 0) + (parseFloat(row.cost) || 0);
}

let severity = null;
if (pctUsed >= 100) severity = 'critical';
else if (pctUsed >= 80) severity = 'warning';

return [{ json: {
  totalSpend: Math.round(totalSpend * 100) / 100,
  dailyBudget,
  pctUsed,
  severity,
  overBudget: severity !== null,
  campaignSpend
} }];

// Build budget alert payload for TG-113
const { totalSpend, dailyBudget, pctUsed, severity, campaignSpend } = $json;

const campaignRows = Object.entries(campaignSpend)
  .sort((a, b) => b[1] - a[1])
  .map(([name, cost]) => `<tr><td style="padding: 4px 8px;">${name}</td><td style="padding: 4px 8px; text-align: right;">$${cost.toFixed(2)}</td></tr>`)
  .join('');

const statusLabel = pctUsed >= 100 ? 'OVER BUDGET' : 'APPROACHING BUDGET';

const html = `<h3 style="margin: 0 0 8px;">Google Ads Budget Alert: ${statusLabel}</h3>
<p style="margin: 0 0 12px;">Daily spend has reached <strong>${pctUsed.toFixed(1)}%</strong> of the $${dailyBudget.toFixed(2)} daily budget.</p>
<table style="font-size: 14px; margin-bottom: 12px;">
  <tr><td style="padding: 4px 0;"><strong>Total Spend Today:</strong></td><td style="padding: 4px 8px;">$${totalSpend.toFixed(2)}</td></tr>
  <tr><td style="padding: 4px 0;"><strong>Daily Budget:</strong></td><td style="padding: 4px 8px;">$${dailyBudget.toFixed(2)}</td></tr>
  <tr><td style="padding: 4px 0;"><strong>Utilization:</strong></td><td style="padding: 4px 8px;">${pctUsed.toFixed(1)}%</td></tr>
</table>
<h4 style="margin: 12px 0 4px;">Campaign Breakdown</h4>
<table style="width: 100%; border-collapse: collapse; font-size: 13px;">
  <thead><tr style="background: #f3f4f6;"><th style="padding: 4px 8px; text-align: left;">Campaign</th><th style="padding: 4px 8px; text-align: right;">Spend</th></tr></thead>
  <tbody>${campaignRows}</tbody>
</table>`;

return [{ json: {
  alert_type: 'budget_exceeded',
  alert_title: `Ad Budget ${statusLabel}: $${totalSpend.toFixed(2)} / $${dailyBudget.toFixed(2)} (${pctUsed.toFixed(1)}%)`,
  alert_body: html,
  severity,
  source_workflow: 'TG-111',
  metadata: { totalSpend, dailyBudget, pctUsed, campaignSpend }
} }];

// Budget within normal range — no alert needed
const { totalSpend, dailyBudget, pctUsed } = $json;
return [{ json: {
  status: 'within_budget',
  totalSpend,
  dailyBudget,
  pctUsed,
  message: `Spend $${totalSpend.toFixed(2)} is ${pctUsed.toFixed(1)}% of $${dailyBudget.toFixed(2)} budget — within normal range`,
  timestamp: new Date().toISOString()
} }];
